// === WF-07 [1] Resolve Period & Mode ===
// Нормализует входные данные из двух источников (Webhook / Schedule)
// в единый формат: { chatId, period, mode, isFromCron }.

const raw  = $input.first().json || {};
const body = raw.body || raw;

// Признак запуска по расписанию: у Schedule Trigger в payload есть
// поля timestamp / Readable date / hour и нет body.chatId.
const isFromCron = !body || (!body.chatId && !body.mode);

// chatId из webhook (manual /reconcile, /missing, /report)
let chatId = '';
if (!isFromCron) {
  chatId = String(body.chatId || body.chat_id || '').trim();
}

// mode: для cron всегда reconcile; для webhook — то, что прислал WF-01
let mode = isFromCron ? 'reconcile' : String(body.mode || 'reconcile').toLowerCase();
if (!['reconcile', 'missing', 'report'].includes(mode)) mode = 'reconcile';

// Period:
//   webhook /reconcile с YYYY-MM → этот период
//   webhook /reconcile без аргумента → текущий месяц
//   webhook /missing, /report → текущий месяц (для отчёта)
//   cron → предыдущий месяц
const now = new Date();
let year, month;

if (isFromCron) {
  // Предыдущий месяц
  const d = new Date(now.getFullYear(), now.getMonth() - 1, 1);
  year  = d.getFullYear();
  month = d.getMonth() + 1;
} else {
  const rawPeriod = String(body.period || '').trim();
  const m = rawPeriod.match(/^(\d{4})-(\d{2})$/);
  if (m) {
    year  = parseInt(m[1], 10);
    month = parseInt(m[2], 10);
  } else {
    year  = now.getFullYear();
    month = now.getMonth() + 1;
  }
}

const period   = `${year}.${String(month).padStart(2, '0')}`;        // 2026.02
const periodIso = `${year}-${String(month).padStart(2, '0')}`;        // 2026-02
const monthNames = ['', 'январь','февраль','март','апрель','май','июнь','июль','август','сентябрь','октябрь','ноябрь','декабрь'];
const monthRu = monthNames[month];

// Границы периода для шаблонов (DD.MM.YYYY)
const pad = n => String(n).padStart(2, '0');
const lastDay = new Date(year, month, 0).getDate();
const periodFromDdmmyyyy = `01.${pad(month)}.${year}`;
const periodToDdmmyyyy   = `${pad(lastDay)}.${pad(month)}.${year}`;

// Маршрут для Switch: 0=reconcile, 1=missing, 2=report
const routeIndex = mode === 'reconcile' ? 0 : (mode === 'missing' ? 1 : 2);

return [{ json: {
  chatId,
  isFromCron,
  mode,
  period,
  periodIso,
  periodLabel: `${monthRu} ${year}`,
  periodFromDdmmyyyy,
  periodToDdmmyyyy,
  routeIndex
}}];

// ============================================================
// WF-07 [4] Match Engine — упрощённый алгоритм PATCH v1.1.
//
// Шаги для каждой банковской транзакции:
//   Шаг 0 (ОБЯЗАТЕЛЬНЫЙ предфильтр):
//          Страна банк == Страна реестр
//          Статус банк == Статус реестр
//          abs(реестр.Сумма) ≈ банк.Сумма  (допуск ±0.3)
//          Валюта банк == Валюта реестр  (без учёта регистра)
//   Шаг 1 (приоритетный):
//          normalize(банк.Номер инвойса) == normalize(реестр.Номер инвойса)
//          (только если оба поля не пусты)
//   Шаг 2 (fallback):
//          normalize(банк.Контрагент) == normalize(реестр.Контрагент)
//
// Несколько кандидатов — берём первого, добавляем [ambiguous] в описание.
// ============================================================

const meta = $('Resolve Period & Mode').first().json;
const { chatId, period, periodLabel, periodFromDdmmyyyy, periodToDdmmyyyy, isFromCron } = meta;

const AMOUNT_TOLERANCE = 30;

// ---------- Утилиты ----------
function normalizeInvoice(s) {
  if (s === null || s === undefined) return '';
  const v = String(s).trim();
  if (!v) return '';
  return v.toLowerCase().replace(/\s+/g, '');
}

function normalizeCounterparty(s) {
  if (s === null || s === undefined) return '';
  // Любой не-буквенно-цифровой символ -> пробел (точки в "sp. z o.o." и кавычки тоже).
  let n = String(s).toLowerCase()
    .replace(/[^a-zа-яё0-9]+/gi, ' ')
    .replace(/\s+/g, ' ')
    .trim();
  if (!n) return '';
  // Многословные латинские юр.формы (\b для латиницы работает корректно).
  n = n.replace(/\bsp\s*z\s*o\s*o\b/g, ' ')
       .replace(/\bs\s*a\b/g, ' ')
       .replace(/\bsp\s*[jk]\b/g, ' ');
  // Однословные юр.формы (RU/BY/PL/EN) удаляем как целые токены — script-agnostic,
  // не зависит от \b (который в JS не видит границы кириллицы).
  const drop = new Set(['ооо','зао','оао','одо','чуп','уп','ип','spzoo','zoo','sa','spj','spk','ltd','llc','gmbh','inc','sarl','sas']);
  n = n.split(' ').filter(t => t && !drop.has(t)).join(' ').trim();
  return n;
}

// Парсер DD.MM.YYYY → YYYY.MM (для извлечения периода из реестра)
function periodFromRegistryRow(r) {
  // Приоритет: Дата оплаты (это и есть момент проводки), fallback Дата документа
  const tryDate = (s) => {
    const m = String(s || '').trim().match(/^(\d{2})\.(\d{2})\.(\d{4})$/);
    return m ? `${m[3]}.${m[2]}` : '';
  };
  return tryDate(r['Дата оплаты']) || tryDate(r['Дата документа']);
}

function toNumber(v) {
  if (typeof v === 'number') return v;
  const s = String(v || '').replace(/\s/g, '').replace(',', '.').replace(/[^0-9.\-]/g, '');
  const n = parseFloat(s);
  return isNaN(n) ? 0 : n;
}

// Сигнатура суммы — только значащие цифры (253892.52 -> "25389252").
function amountSignature(v) {
  return String(v == null ? '' : v).replace(/[^\d]/g, '').replace(/^0+/, '');
}
// Множество цифровых сигнатур всех числовых токенов из текста описания.
function numberSignatures(desc) {
  const set = new Set();
  const tokens = String(desc == null ? '' : desc).match(/\d[\d.,\u00A0 \-]*\d|\d/g) || [];
  for (const tok of tokens) {
    const sig = tok.replace(/[^\d]/g, '').replace(/^0+/, '');
    if (sig) set.add(sig);
  }
  return set;
}

// ---------- Чтение исходников ----------
const rawBankAll = $('Read Bank Sheet').all().map(i => i.json).filter(r => r && r['bank_id']);
const rawRegAll  = $('Read Registry Sheet').all().map(i => i.json).filter(r => r && r['Nr ID']);

// Фильтр банка: период + статус сверки in {PENDING, UNMATCHED}
const bankRows = rawBankAll.filter(r => {
  if (String(r['Период']).trim() !== period) return false;
  const status = String(r['Статус сверки'] || '').trim().toUpperCase();
  return status === 'PENDING' || status === 'UNMATCHED' || status === '';
});

// Фильтр реестра: период (по дате оплаты/документа) + Статус оплаты = Оплачено
const regRows = rawRegAll.filter(r => {
  const payStatus = String(r['Статус оплаты'] || '').trim();
  if (payStatus !== 'Оплачено') return false;
  const rowPeriod = periodFromRegistryRow(r);
  return rowPeriod === period;
});

// Если по этому периоду нечего сверять — выходим с пустым результатом
if (bankRows.length === 0) {
  return [{ json: {
    chatId,
    isFromCron,
    period,
    periodLabel,
    periodFromDdmmyyyy,
    periodToDdmmyyyy,
    noWorkToDo: true,
    bankCount: 0,
    regCount: regRows.length,
    bankUpdates: [],
    reconciliationRows: [],
    statsBy: { total: 0, matched: 0, unmatched: 0, bank: '' },
    statsPl: { total: 0, matched: 0, unmatched: 0, bank: '' },
    unmatchedBy: [],
    unmatchedPl: []
  }}];
}

// ---------- Алгоритм матчинга ----------
const results = [];
// Реестровые строки, уже занятые кросс-валютным матчем (Шаг 3) — чтобы не привязать
// один инвойс к двум платежам. UUID реестра как ключ.
const usedRegUuids = new Set();

for (const tx of bankRows) {
  const bankAmount   = toNumber(tx['Сумма']);
  const bankCurrency = String(tx['Валюта'] || '').toUpperCase();

  // Шаг 0: предфильтр
  const candidates = regRows.filter(r => {
    if (String(r['Страна']).trim() !== String(tx['Страна']).trim()) return false;
    if (String(r['Статус']).trim() !== String(tx['Статус']).trim()) return false;
    if (String(r['Валюта'] || '').toUpperCase().trim() !== bankCurrency) return false;
    const regAmount = Math.abs(toNumber(r['Сумма']));
    return Math.abs(regAmount - bankAmount) <= AMOUNT_TOLERANCE;
  });

  let matched = null;
  let ambiguous = false;
  let matchedBy = '';

  if (candidates.length > 0) {
    // Шаг 1: по номеру инвойса
    const bInv = normalizeInvoice(tx['Номер инвойса (банк)']);
    if (bInv) {
      const hits = candidates.filter(r => normalizeInvoice(r['Номер инвойса']) === bInv);
      if (hits.length > 0) {
        matched   = hits[0];
        ambiguous = hits.length > 1;
        matchedBy = 'invoice';
      }
    }

    // Шаг 2: по контрагенту
    if (!matched) {
      const bCp = normalizeCounterparty(tx['Контрагент']);
      if (bCp) {
        const hits = candidates.filter(r => normalizeCounterparty(r['Контрагент']) === bCp);
        if (hits.length > 0) {
          matched   = hits[0];
          ambiguous = hits.length > 1;
          matchedBy = 'counterparty';
        }
      }
    }
  }

  // Шаг 3 (кросс-валютный): инвойс в иностранной валюте (напр. RUB) оплачивается
  // в местной валюте после конвертации. Суммы и валюты не совпадают (Шаг 0 их не
  // связывает), а инвойс часто «Не оплачено» и датирован другим месяцем — поэтому
  // ищем по ВСЕМУ реестру (rawRegAll), без фильтра периода/оплаты. Признак —
  // точная сумма инвойса присутствует в описании банковской операции
  // (Приорбанк указывает её в назначении: …SUMMA 253892-52…).
  if (!matched) {
    const bSigs = numberSignatures(tx['Описание']);
    if (bSigs.size) {
      const bCountry = String(tx['Страна']).trim();
      const bStatus  = String(tx['Статус']).trim();
      const hit = rawRegAll.find(r => {
        if (usedRegUuids.has(String(r['UUID'] || ''))) return false;
        if (String(r['Страна']).trim() !== bCountry) return false;
        if (String(r['Статус']).trim() !== bStatus) return false;
        if (String(r['Валюта'] || '').toUpperCase().trim() === bankCurrency) return false; // только кросс-валютные
        const rSig = amountSignature(r['Сумма']);
        return rSig && bSigs.has(rSig);
      });
      if (hit) {
        matched = hit;
        matchedBy = 'cross-currency';
        usedRegUuids.add(String(hit['UUID'] || ''));
      }
    }
  }

  results.push({ tx, matched, ambiguous, matchedBy });
}

// ---------- Сборка апдейтов листа «Банк» ----------
const bankUpdates = results.map(({ tx, matched, ambiguous }) => {
  const newStatus = matched ? 'MATCHED' : 'UNMATCHED';
  const newUuid   = matched ? String(matched['UUID'] || '') : '';
  // Описание дополняем меткой [ambiguous] однократно
  let description = String(tx['Описание'] || '');
  if (ambiguous && !description.includes('[ambiguous]')) {
    description = (description ? description + ' ' : '') + '[ambiguous]';
  }
  return {
    'bank_id':        tx['bank_id'],
    'Статус сверки':  newStatus,
    'UUID реестра':   newUuid,
    'Описание':       description
  };
});

// ---------- Сборка строк листа «Сверка» (12 колонок) ----------
const reconciliationRows = results.map(({ tx, matched }) => ({
  'bank_id':              tx['bank_id'] || '',
  'Страна':               tx['Страна']  || '',
  'Банк':                 tx['Банк']    || '',
  'Дата операции':        tx['Дата документа'] || '',
  'Сумма':                toNumber(tx['Сумма']),
  'Валюта':               String(tx['Валюта'] || '').toUpperCase(),
  'Статус':               tx['Статус'] || '',
  'Контрагент (банк)':    tx['Контрагент'] || '',
  'Статус сверки':        matched ? 'MATCHED' : 'UNMATCHED',
  'Nr ID (реестр)':       matched ? String(matched['Nr ID'] || '') : '',
  'Контрагент (реестр)':  matched ? String(matched['Контрагент'] || '') : '',
  'UUID реестра':         matched ? String(matched['UUID'] || '') : ''
}));

// ---------- Статистика по странам ----------
function stats(rows, country) {
  const subset = rows.filter(r => r['Страна'] === country);
  const matchedCnt = subset.filter(r => r['Статус сверки'] === 'MATCHED').length;
  const unmatched  = subset.filter(r => r['Статус сверки'] === 'UNMATCHED');
  // Банк-метка: уникальный банк, если он один (чаще всего так)
  const banks = Array.from(new Set(subset.map(r => r['Банк']).filter(Boolean)));
  const bankLabel = banks.length === 1
    ? (banks[0] === 'PKO_BP' ? 'PKO Bank Polski' : 'Priorbank')
    : banks.join(', ');
  return {
    total: subset.length,
    matched: matchedCnt,
    unmatched: unmatched.length,
    bank: bankLabel,
    unmatchedRows: unmatched
  };
}

const byStats = stats(reconciliationRows, 'Беларусь');
const plStats = stats(reconciliationRows, 'Польша');

return [{ json: {
  chatId,
  isFromCron,
  period,
  periodLabel,
  periodFromDdmmyyyy,
  periodToDdmmyyyy,
  noWorkToDo: false,
  bankCount: bankRows.length,
  regCount:  regRows.length,
  bankUpdates,
  reconciliationRows,
  statsBy: {
    total:     byStats.total,
    matched:   byStats.matched,
    unmatched: byStats.unmatched,
    bank:      byStats.bank
  },
  statsPl: {
    total:     plStats.total,
    matched:   plStats.matched,
    unmatched: plStats.unmatched,
    bank:      plStats.bank
  },
  unmatchedBy: byStats.unmatchedRows,
  unmatchedPl: plStats.unmatchedRows
}}];

// === WF-07 [5a] Explode Bank Updates ===
// Берём bankUpdates из Match Engine и эмитим N items для Update Bank Sheet.
// Если массив пуст — создаём один служебный item, чтобы цепочка не оборвалась.

const meta = $('Match Engine').first().json;
const updates = meta.bankUpdates || [];

if (updates.length === 0) {
  return [{ json: { _empty: true, bank_id: '', 'Статус сверки': '', 'UUID реестра': '', 'Описание': '' } }];
}

return updates.map(u => ({ json: u }));

// === WF-07 [6a] Explode Reconciliation Rows ===
// Берём reconciliationRows из Match Engine и эмитим N items для Append.

const meta = $('Match Engine').first().json;
const rows = meta.reconciliationRows || [];

if (rows.length === 0) {
  // Лист уже очищен; ничего не добавляем.
  return [{ json: {
    _empty: true,
    'bank_id': '', 'Страна': '', 'Банк': '', 'Дата операции': '',
    'Сумма': 0, 'Валюта': '', 'Статус': '', 'Контрагент (банк)': '',
    'Статус сверки': '', 'Nr ID (реестр)': '', 'Контрагент (реестр)': '', 'UUID реестра': ''
  }}];
}

return rows.map(r => ({ json: r }));

// === WF-07 [7] Build Reconcile Notification ===
// Формирует текст уведомления по шаблону §2.7 PRD.
// Закрытый месяц / открытый месяц — два разных шаблона.

const m = $('Match Engine').first().json;
const spreadsheetUrl = `https://docs.google.com/spreadsheets/d/${$env.GOOGLE_SHEETS_ID}/edit`;

const flagBy = '\uD83C\uDDE7\uD83C\uDDFE'; // 🇧🇾
const flagPl = '\uD83C\uDDF5\uD83C\uDDF1'; // 🇵🇱

function fmtAmount(n) {
  const v = Number(n) || 0;
  return Number.isInteger(v) ? String(v) : v.toFixed(2);
}

function shortDate(ddmmyyyy) {
  // 14.02.2026 → 14.02
  const m = String(ddmmyyyy || '').match(/^(\d{2})\.(\d{2})\.\d{4}$/);
  return m ? `${m[1]}.${m[2]}` : (ddmmyyyy || '—');
}

const by = m.statsBy;
const pl = m.statsPl;
const byBank = by.bank || 'Priorbank';
const plBank = pl.bank || 'PKO Bank Polski';

// Закрытый месяц по странам?
const byClosed = by.total > 0 && by.unmatched === 0;
const plClosed = pl.total > 0 && pl.unmatched === 0;
const byEmpty  = by.total === 0;
const plEmpty  = pl.total === 0;
const allClosedOrEmpty = (byClosed || byEmpty) && (plClosed || plEmpty);

// === Шаблон закрытого месяца ===
function buildClosedTemplate() {
  const lines = [
    `\u2705 Сверка за ${m.periodLabel} завершена`,
    `Период: ${m.periodFromDdmmyyyy} \u2014 ${m.periodToDdmmyyyy}`,
    ''
  ];
  if (by.total > 0) {
    lines.push(`${flagBy} Беларусь (${byBank}) \u2014 все ${by.total} транзакций закрыты`);
  } else {
    lines.push(`${flagBy} Беларусь \u2014 нет банковских транзакций за период`);
  }
  if (pl.total > 0) {
    lines.push(`${flagPl} Польша (${plBank}) \u2014 все ${pl.total} транзакций закрыты`);
  } else {
    lines.push(`${flagPl} Польша \u2014 нет банковских транзакций за период`);
  }
  lines.push('');
  lines.push('Месяц закрыт без замечаний.');
  lines.push('');
  lines.push(`\uD83D\uDCCA Реестр: ${spreadsheetUrl}`);
  return lines.join('\n');
}

// === Шаблон с незакрытыми позициями ===
function buildOpenTemplate() {
  const lines = [
    `\uD83D\uDCCB Сверка за ${m.periodLabel} завершена`,
    `Период: ${m.periodFromDdmmyyyy} \u2014 ${m.periodToDdmmyyyy}`,
    ''
  ];

  // Секция BY
  if (by.total > 0) {
    lines.push(`${flagBy} Беларусь (${byBank})`);
    lines.push(`\u2705 Закрыто: ${by.matched} из ${by.total} | \u274C Без документа: ${by.unmatched}`);
    lines.push('');
  }
  // Секция PL
  if (pl.total > 0) {
    lines.push(`${flagPl} Польша (${plBank})`);
    lines.push(`\u2705 Закрыто: ${pl.matched} из ${pl.total} | \u274C Без документа: ${pl.unmatched}`);
    lines.push('');
  }

  // Список незакрытых
  const unmatchedTotal = (m.unmatchedBy || []).length + (m.unmatchedPl || []).length;
  if (unmatchedTotal > 0) {
    lines.push('\u2501\u2501\u2501 Незакрытые позиции \u2501\u2501\u2501');
    const formatRow = (r, flag) => {
      const cp = r['Контрагент (банк)'] || '\u2014';
      return `${flag} ${shortDate(r['Дата операции'])} | ${fmtAmount(r['Сумма'])} ${r['Валюта']} | ${r['Статус']} | ${cp}`;
    };
    (m.unmatchedBy || []).forEach(r => lines.push(formatRow(r, flagBy)));
    (m.unmatchedPl || []).forEach(r => lines.push(formatRow(r, flagPl)));
    lines.push('');
    lines.push('Добавьте недостающие документы через бот.');
    lines.push('');
  }

  lines.push(`\uD83D\uDCCA Реестр: ${spreadsheetUrl}`);
  return lines.join('\n');
}

const text = allClosedOrEmpty ? buildClosedTemplate() : buildOpenTemplate();

return [{ json: {
  chatId: m.chatId,
  isFromCron: m.isFromCron,
  notificationText: text,
  period: m.period
}}];

// === WF-07 [8] Build Recipients ===
// Формирует список chat_id, которым нужно отправить уведомление.
// MVP-логика:
//   - manual /reconcile (есть chatId) → один получатель
//   - cron (chatId пустой)            → TELEGRAM_ADMIN_CHAT_ID (через запятую)

const inp = $input.first().json;
const notificationText = inp.notificationText;
const period = inp.period;

let recipients = [];
if (inp.chatId) {
  recipients = [String(inp.chatId)];
} else {
  recipients = String($env.TELEGRAM_ADMIN_CHAT_ID || '')
    .split(',')
    .map(s => s.trim())
    .filter(Boolean);
}

if (recipients.length === 0) {
  // Защита: если ни одного получателя — отправлять некуда, но цепочка не должна падать.
  return [{ json: { _empty: true, chatId: '', notificationText, period }}];
}

return recipients.map(chatId => ({
  json: { chatId, notificationText, period, _empty: false }
}));

// === WF-07 [E1] Build No-Data Notification ===
// Если нет банковских транзакций для сверки за период.

const m = $('Match Engine').first().json;
const spreadsheetUrl = `https://docs.google.com/spreadsheets/d/${$env.GOOGLE_SHEETS_ID}/edit`;

const text =
`\u2139\uFE0F Сверка за ${m.periodLabel}
Период: ${m.periodFromDdmmyyyy} \u2014 ${m.periodToDdmmyyyy}

Нет банковских транзакций для сверки.
Загрузите выписку через /vpsk и повторите /reconcile.

\uD83D\uDCCA Реестр: ${spreadsheetUrl}`;

// Получатель: либо chatId, либо TELEGRAM_ADMIN_CHAT_ID
let recipients = [];
if (m.chatId) {
  recipients = [String(m.chatId)];
} else {
  recipients = String($env.TELEGRAM_ADMIN_CHAT_ID || '')
    .split(',').map(s => s.trim()).filter(Boolean);
}

if (recipients.length === 0) {
  return [{ json: { _empty: true, chatId: '', notificationText: text, period: m.period }}];
}

return recipients.map(chatId => ({
  json: { chatId, notificationText: text, period: m.period, _empty: false }
}));

// === WF-07 [M] Build Missing Message ===
// Читает лист «Сверка» (последний снимок) и формирует список UNMATCHED.
// Период игнорируется — лист всегда хранит последнюю сверку.

const m = $('Resolve Period & Mode').first().json;
const rows = $input.all().map(i => i.json).filter(r => r && r['bank_id']);
const spreadsheetUrl = `https://docs.google.com/spreadsheets/d/${$env.GOOGLE_SHEETS_ID}/edit`;

const flagBy = '\uD83C\uDDE7\uD83C\uDDFE';
const flagPl = '\uD83C\uDDF5\uD83C\uDDF1';

function fmtAmount(n) {
  const v = Number(n) || 0;
  return Number.isInteger(v) ? String(v) : v.toFixed(2);
}
function shortDate(ddmmyyyy) {
  const x = String(ddmmyyyy || '').match(/^(\d{2})\.(\d{2})\.\d{4}$/);
  return x ? `${x[1]}.${x[2]}` : (ddmmyyyy || '\u2014');
}

// Если лист пустой → сверки ещё не было
if (rows.length === 0) {
  const text =
`\u2139\uFE0F Сверка ещё не запускалась

Запустите /reconcile или дождитесь автосверки 1-го числа.

\uD83D\uDCCA Реестр: ${spreadsheetUrl}`;
  return [{ json: { chatId: m.chatId, notificationText: text }}];
}

const unmatched = rows.filter(r => String(r['Статус сверки']).trim() === 'UNMATCHED');
const byList = unmatched.filter(r => r['Страна'] === 'Беларусь');
const plList = unmatched.filter(r => r['Страна'] === 'Польша');

const lines = [`\uD83D\uDCCB Незакрытые позиции (последняя сверка)`, ''];

if (byList.length > 0) {
  lines.push(`${flagBy} Беларусь \u2014 ${byList.length}`);
  byList.forEach(r => {
    const cp = r['Контрагент (банк)'] || '\u2014';
    lines.push(`  ${shortDate(r['Дата операции'])} | ${fmtAmount(r['Сумма'])} ${r['Валюта']} | ${r['Статус']} | ${cp}`);
  });
  lines.push('');
}
if (plList.length > 0) {
  lines.push(`${flagPl} Польша \u2014 ${plList.length}`);
  plList.forEach(r => {
    const cp = r['Контрагент (банк)'] || '\u2014';
    lines.push(`  ${shortDate(r['Дата операции'])} | ${fmtAmount(r['Сумма'])} ${r['Валюта']} | ${r['Статус']} | ${cp}`);
  });
  lines.push('');
}

if (byList.length === 0 && plList.length === 0) {
  lines.length = 0;
  lines.push(`\u2705 Все позиции последней сверки закрыты.`);
  lines.push('');
}

lines.push(`\uD83D\uDCCA Реестр: ${spreadsheetUrl}`);

return [{ json: {
  chatId: m.chatId,
  notificationText: lines.join('\n')
}}];

